import json

with open('baseline-packages-captured.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: {(project_basename, framework, package_id): resolved_version}
def build_lookup(data):
    lookup = {}
    for proj in data.get('projects', []):
        pname = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            tfm = fw['framework']
            for pkg in fw.get('topLevelPackages', []):
                lookup[(pname, tfm, pkg['id'])] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    proj, tfm, pkg = k
    bv = b.get(k)
    av = a.get(k)
    if bv is None:
        changes.append((proj, tfm, pkg, '—', av, 'Added'))
    elif av is None:
        changes.append((proj, tfm, pkg, bv, '—', 'Removed'))
    elif bv != av:
        changes.append((proj, tfm, pkg, bv, av, 'Aligned to highest version'))
    else:
        unchanged.append((proj, tfm, pkg, bv))

if changes:
    print('=== CHANGES ===')
    print(f'{'Project':<16} {'TFM':<10} {'Package':<50} {'Before':<12} {'After':<12} Status')
    for c in changes:
        print(f'{c[0]:<16} {c[1]:<10} {c[2]:<50} {c[3]:<12} {c[4]:<12} {c[5]}')
else:
    print('No changes detected.')

print()
print(f'=== UNCHANGED ({len(unchanged)} entries) ===')
print(f'{'Project':<16} {'TFM':<10} {'Package':<50} {'Version':<12}')
for u in unchanged:
    print(f'{u[0]:<16} {u[1]:<10} {u[2]:<50} {u[3]:<12}')
"

